# Spring Boot application.properties
spring.security.oauth2.resourceserver.jwt.jwk-set-uri=
  https://cognito-idp.us-east-1.amazonaws.com/us-east-1_ABC123/.well-known/jwks.json

# SecurityConfig
@Bean
SecurityFilterChain chain(HttpSecurity http) throws Exception {
    http
        .authorizeHttpRequests(auth -> auth
            .requestMatchers("/public/**").permitAll()
            .anyRequest().authenticated())
        .oauth2ResourceServer(oauth2 -> oauth2.jwt(Customizer.withDefaults()));
    return http.build();
}

// Spring Boot + AWS Secrets Manager (spring-cloud-aws)
// application.yml
spring:
  cloud:
    aws:
      secretsmanager:
        enabled: true

// Inject secret
@Value("${/prod/myapp/db-password}")
private String dbPassword;

// Direct SDK
SecretsManagerClient client = SecretsManagerClient.create();
GetSecretValueResponse resp = client.getSecretValue(
    r -> r.secretId("/prod/myapp/db-password")
);
String secret = resp.secretString();

# Step Functions use case: order processing workflow
# States: ValidateOrder → ChargePayment → UpdateInventory → SendConfirmation
{
  "StartAt": "ValidateOrder",
  "States": {
    "ValidateOrder": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:...:ValidateOrderFunction",
      "Retry": [{ "ErrorEquals": ["States.ALL"], "MaxAttempts": 2 }],
      "Catch": [{ "ErrorEquals": ["ValidationError"], "Next": "OrderFailed" }],
      "Next": "ChargePayment"
    },
    "ChargePayment": { "Type": "Task", ... }
  }
}
